import { Point } from '@visx/brush/lib/types';
import { useCallback } from 'react';

import Colors from '@dynatrace/strato-design-tokens/colors';
import Typography from '@dynatrace/strato-design-tokens/typography';

import { getTokenComputedStyle } from '../../../../../utils/getTokenComputedStyle.js';
import { useCanvas } from '../../../../canvas/hooks/useCanvas.js';
import { charsFontWidth12pixelsSize400Map } from '../../../../text-ellipsis/chars-font-width-map.js';
import {
  calculateWidth,
  truncateString,
} from '../../../../text-ellipsis/truncate-string.js';

interface AnnotationsLabelRendererProps extends Point {
  text: string;
  maxWidth?: number;
  textAlign?: CanvasTextAlign;
  ellipsis?: boolean;
}

const getLabelFont = () => {
  const fontSize = getTokenComputedStyle(Typography.Text.Small.Default.Size);
  const fontFamily = getTokenComputedStyle(
    Typography.Text.Small.Default.Family,
  );

  const fontWeight = getTokenComputedStyle(
    Typography.Text.Small.Default.Weight,
  );

  return [fontWeight, fontSize, fontFamily];
};

export const AnnotationsLabelRenderer = (
  props: AnnotationsLabelRendererProps,
) => {
  const {
    text: originalText,
    x,
    y,
    maxWidth,
    textAlign = 'right',
    ellipsis,
  } = props;

  const color = getTokenComputedStyle(Colors.Text.Neutral.Subdued);

  const [fontWeight, fontSize, fontFamily] = getLabelFont();

  const font = [fontWeight, fontSize, fontFamily].join(' ');

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      ctx.font = font;

      const textWidth = calculateWidth(
        originalText,
        charsFontWidth12pixelsSize400Map,
      );
      const applyEllipsis = ellipsis && maxWidth && textWidth > maxWidth;
      const textToRender = applyEllipsis
        ? truncateString(
            originalText,
            maxWidth,
            charsFontWidth12pixelsSize400Map,
            'end',
          )
        : originalText;
      ctx.textAlign = textAlign;
      ctx.fillStyle = color;
      ctx.textBaseline = 'middle';

      ctx.fillText(textToRender, x, y, maxWidth);

      return false;
    },
    [originalText, x, y, maxWidth],
  );

  useCanvas('annotations-label', draw);

  return null;
};

AnnotationsLabelRenderer['displayName'] = 'AnnotationsLabelRenderer';
